INSERT INTO public.cycling_events ("id", "title", "description", "county_id", "region", "date", ""time"", "meeting_point", "meeting_point_url", "cover_image", "distance", "elevation", "pace", "max_participants", "strava_route_url", "moak_event_id", "sticky_color", "tags", "creator_id", "created_at", "route_coordinates", "series_id", "recurrence_type") VALUES ('evt-1775032024703-rr2z1', '2026 DEDA Ride 國王盃：中寮約騎大挑戰', '🛣️ 路線：
南投縣中寮鄉和興社區發展協會到觀音亭販賣機

⚠️ 注意事項：
🏆 2026 DEDA 國王盃中寮約騎大挑戰

📅 活動期間：4/12 – 4/12
🚴 距離：5.7 km
⛰️ 爬升：5.9%

「一起騎車，一起快樂」

• 這不只是一場比賽，是一次自我挑戰的旅程。
• 中寮的緩坡與綠意，正是與車友交流、拉強度最棒的舞台。
• 不論你是為了超越巔峰，還是為了終點後的熱血合照，DEDA 都將與你同行。

獎品：
第1名： DEDA 碟盤 (一車份)  
第2名： DEDA 三鐵包  
第3名： DEDA 把帶 (一年份，每季幫你換一條新的)  
第4-6 名： DEDA 水壺架 (一車份)  
隱藏福利： 車上有 DEDA 零件的，來找我拿神秘小禮物。  
• 前50位名額可以獲得200元憲金券 (限於當日使用於和興村相關食物與飲品) 以報名順序為依據，當日未到就往下遞延。

🔗 [連結已移除]

