INSERT INTO public.tcuad_placements ("id", "created_at", "brand_name", "product_name", "product_url", "description", "trigger_keywords", "placement_text", "priority", "is_active", "start_date", "end_date", "current_impressions", "max_impressions", "image_url", "location_tags") VALUES ('05bd484a-a2a9-4625-b384-efd7dcb42120', '2026-02-13 07:38:27.458812+00', 'SIS 英國運動科學', 'SiS 高能量果膠 (黑膠)', 'https://www.scienceinsport.tw/products/beta-fuel-gel-1', '當使用者進行高強度、長距離耐力訓練，且消化系統強健時推薦。適合在需要高密度碳水化合物攝入時使用（如賽前或高強度區間）。', '{黑膠,高強度,長距離,賽前補給,雙倍碳水,1:0.8,耐力訓練,追求極限}', '黑膠擁有全新的 1:0.8 雙源碳水配方，吸收效率比舊配方提升 74%。它屬於高滲透壓產品，能量密度更高，非常適合高強度的耐力挑戰。建議您依個人消化狀況，於運動或訓練前 20-30 分鐘攝入，為身體儲備強大動能。

"1. 區分黑膠與銀膠：如果使用者是初學者或容易腸胃不適，優先推薦銀膠（等滲透，低風險）。如果使用者是菁英選手或強調極限耐力，可推薦黑膠，但需提醒提早攝入（消化時間較長）。
2. 碳水攝入量計算：若使用者詢問吃多少，可依據公式判斷：
    ◦ 綜合/高爆發型：體重(kg) × 0.5g~0.6g
    ◦ 高有氧型：體重(kg) × 0.8g~1g (視強度可更高，如環法選手可達 1.2g)
3. 時機判斷：
    ◦ 運動前 15-30 分鐘：推薦黑膠（需消化）或銀膠。
    ◦ 運動中 (即時)：強烈推薦銀膠（吸收快、不脹氣）。
    ◦ 運動後：推薦 REGO 恢復系列。
"', '9', 'f', '2026-02-12', '2029-07-01', '0', NULL, NULL, '{騎車,article_bottom,sidebar,homepage_banner}') ON CONFLICT DO NOTHING;
