INSERT INTO public.tcuad_placements ("id", "created_at", "brand_name", "product_name", "product_url", "description", "trigger_keywords", "placement_text", "priority", "is_active", "start_date", "end_date", "current_impressions", "max_impressions", "image_url", "location_tags") VALUES ('2557a166-36ff-4596-9b2c-6b9b1f86da8e', '2026-03-06 07:35:42.545298+00', '碳水炸彈', '蜂蜜能量膠', 'https://calbomb.com/shop/%e9%bb%91%e7%b3%96%e8%83%bd%e9%87%8f%e8%86%a010%e5%85%a5%e7%b5%84/', '礦物質補給： 黑糖除了提供快速吸收的糖分外，更含有鉀、鎂、鈣等天然微量元素，對維持運動表現有正面幫助。

溫和能量釋放： 天然黑糖的糖分組成能提供穩定的能量支撐，適合用於長距離賽事的後半段，作為提振精神與補充體力的核心方案。

